package sandbox

import "testing"

func TestReverseRunes(t *testing.T) {
	tests := []struct {
		name string
		in   string
		want string
	}{
		{"empty", "", ""},
		{"single ascii", "x", "x"},
		{"ascii", "abc", "cba"},
		{"ascii palindrome", "aba", "aba"},
		{"accented multibyte", "héllo", "olléh"},
		{"cjk", "日本語", "語本日"},
		{"emoji between ascii", "a😀b", "b😀a"},
		{"mixed widths", "go café", "éfac og"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := ReverseRunes(tt.in)
			if got != tt.want {
				t.Errorf("ReverseRunes(%q) = %q, want %q", tt.in, got, tt.want)
			}
			// Reversing twice must reproduce the original string.
			if round := ReverseRunes(got); round != tt.in {
				t.Errorf("ReverseRunes(ReverseRunes(%q)) = %q, want %q", tt.in, round, tt.in)
			}
		})
	}
}
