package sandbox

import (
	"testing"
	"unicode/utf8"
)

func TestTruncateRunes(t *testing.T) {
	tests := []struct {
		name  string
		in    string
		limit int
		want  string
	}{
		{"shorter than limit", "hello", 10, "hello"},
		{"exact length", "hello", 5, "hello"},
		{"truncate ascii", "hello", 3, "hel"},
		{"zero limit", "hello", 0, ""},
		{"negative limit", "hello", -1, ""},
		{"empty input", "", 5, ""},
		{"multibyte not split", "héllo", 2, "hé"},
		{"cjk", "日本語", 2, "日本"},
		{"emoji", "😀😀😀", 2, "😀😀"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := TruncateRunes(tt.in, tt.limit)
			if got != tt.want {
				t.Errorf("TruncateRunes(%q, %d) = %q, want %q", tt.in, tt.limit, got, tt.want)
			}
			if !utf8.ValidString(got) {
				t.Errorf("TruncateRunes(%q, %d) produced invalid UTF-8: %q", tt.in, tt.limit, got)
			}
			if tt.limit > 0 {
				if n := utf8.RuneCountInString(got); n > tt.limit {
					t.Errorf("TruncateRunes(%q, %d) returned %d runes, want <= %d", tt.in, tt.limit, n, tt.limit)
				}
			}
		})
	}
}
