	tests := []struct {
		name string
		in   string
		want string
	}{
		{"empty", "", ""},
		{"capitalized word", "Hello", "hELLO"},
		{"alternating", "aBcD", "AbCd"},
		{"digits unchanged", "123", "123"},
		{"with spaces and punctuation", "Go, World!", "gO, wORLD!"},
		{"accented", "héllo", "HÉLLO"},
		{"spanish enye", "Ñoño", "ñOÑO"},
		{"ring above", "abcÅ", "ABCå"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := SwapCase(tt.in)
			if got != tt.want {
				t.Errorf("SwapCase(%q) = %q, want %q", tt.in, got, tt.want)
			}
			// For these inputs every cased rune has a single-rune inverse,
			// so applying SwapCase twice restores the original.
			if round := SwapCase(got); round != tt.in {
				t.Errorf("SwapCase(SwapCase(%q)) = %q, want %q", tt.in, round, tt.in)
			}
		})
