package sandbox

import (
	"reflect"
	"strconv"
	"testing"
)

func TestMap(t *testing.T) {
	double := func(n int) int { return n * 2 }
	tests := []struct {
		name string
		in   []int
		f    func(int) int
		want []int
	}{
		{"nil slice yields nil", nil, double, nil},
		{"empty slice yields empty", []int{}, double, []int{}},
		{"single element", []int{3}, double, []int{6}},
		{"several elements", []int{1, 2, 3, 4}, double, []int{2, 4, 6, 8}},
		{"handles negatives and zero", []int{-1, 0, 5}, double, []int{-2, 0, 10}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := Map(tt.in, tt.f)
			if !reflect.DeepEqual(got, tt.want) {
				t.Errorf("Map(%v) = %v, want %v", tt.in, got, tt.want)
			}
			if tt.in == nil && got != nil {
				t.Errorf("Map(nil) = %v, want nil (not empty slice)", got)
			}
		})
	}
}

func TestMapChangesElementType(t *testing.T) {
	in := []int{1, 22, 333}
	got := Map(in, strconv.Itoa)
	want := []string{"1", "22", "333"}
	if !reflect.DeepEqual(got, want) {
		t.Fatalf("Map(strconv.Itoa) = %v, want %v", got, want)
	}
}

func TestMapDoesNotMutateInput(t *testing.T) {
	in := []int{1, 2, 3}
	_ = Map(in, func(n int) int { return n + 100 })
	want := []int{1, 2, 3}
	if !reflect.DeepEqual(in, want) {
		t.Errorf("input was mutated: got %v, want %v", in, want)
	}
}

func TestMapCalledOncePerElementInOrder(t *testing.T) {
	in := []int{10, 20, 30}
	var seen []int
	Map(in, func(n int) int {
		seen = append(seen, n)
		return n
	})
	if !reflect.DeepEqual(seen, in) {
		t.Errorf("f visited %v, want %v (same elements, same order)", seen, in)
	}
}
