package sandbox

import (
	"strconv"
	"testing"
)

func TestReduceSum(t *testing.T) {
	add := func(acc, n int) int { return acc + n }
	tests := []struct {
		name string
		in   []int
		init int
		want int
	}{
		{"nil returns init", nil, 0, 0},
		{"empty returns init", []int{}, 100, 100},
		{"sum from zero", []int{1, 2, 3, 4}, 0, 10},
		{"sum with nonzero init", []int{1, 2, 3}, 10, 16},
		{"mixed signs", []int{-5, 5, -3}, 0, -3},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := Reduce(tt.in, tt.init, add)
			if got != tt.want {
				t.Errorf("Reduce(%v, init=%d, add) = %d, want %d", tt.in, tt.init, got, tt.want)
			}
		})
	}
}

func TestReduceFoldsLeftToRight(t *testing.T) {
	// Subtraction is order-sensitive, so this pins down the fold direction.
	in := []int{1, 2, 3}
	got := Reduce(in, 10, func(acc, n int) int { return acc - n })
	want := 10 - 1 - 2 - 3 // == 4
	if got != want {
		t.Fatalf("Reduce(sub) = %d, want %d (left-to-right fold)", got, want)
	}
}

func TestReduceAccumulatorType(t *testing.T) {
	// Element type int, accumulator type string: concatenate digits.
	in := []int{1, 2, 3}
	got := Reduce(in, "", func(acc string, n int) string {
		return acc + strconv.Itoa(n)
	})
	if got != "123" {
		t.Fatalf("Reduce(concat) = %q, want %q", got, "123")
	}
}

func TestReduceBuildsSlice(t *testing.T) {
	in := []int{1, 2, 3, 4}
	got := Reduce(in, []int(nil), func(acc []int, n int) []int {
		if n%2 == 0 {
			return append(acc, n)
		}
		return acc
	})
	want := []int{2, 4}
	if len(got) != len(want) {
		t.Fatalf("Reduce(collect evens) = %v, want %v", got, want)
	}
	for i := range want {
		if got[i] != want[i] {
			t.Errorf("element %d = %d, want %d", i, got[i], want[i])
		}
	}
}
