func TestChunk(t *testing.T) {
	tests := []struct {
		name string
		in   []int
		size int
		want [][]int
	}{
		{"size zero yields nil", []int{1, 2, 3}, 0, nil},
		{"negative size yields nil", []int{1, 2, 3}, -2, nil},
		{"nil input yields nil", nil, 2, nil},
		{"empty input yields nil", []int{}, 2, nil},
		{"exact division", []int{1, 2, 3, 4}, 2, [][]int{{1, 2}, {3, 4}}},
		{"trailing remainder", []int{1, 2, 3, 4, 5}, 2, [][]int{{1, 2}, {3, 4}, {5}}},
		{"size larger than length", []int{1, 2}, 5, [][]int{{1, 2}}},
		{"size one", []int{1, 2, 3}, 1, [][]int{{1}, {2}, {3}}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := Chunk(tt.in, tt.size)
			if !reflect.DeepEqual(got, tt.want) {
				t.Errorf("Chunk(%v, %d) = %v, want %v", tt.in, tt.size, got, tt.want)
			}
		})
	}
}

func TestChunkCapacityIsClamped(t *testing.T) {
	// Appending to an early chunk must not clobber a later chunk.
	in := []int{1, 2, 3, 4}
	chunks := Chunk(in, 2)
	if len(chunks) != 2 {
		t.Fatalf("got %d chunks, want 2", len(chunks))
	}
	chunks[0] = append(chunks[0], 999)
	if !reflect.DeepEqual(chunks[1], []int{3, 4}) {
		t.Errorf("append to chunk[0] corrupted chunk[1]: got %v, want [3 4]", chunks[1])
	}
}
