	isPositive := func(n int) bool { return n > 0 }
	tests := []struct {
		name        string
		in          []int
		wantMatched []int
		wantRest    []int
	}{
		{"nil yields nil, nil", nil, nil, nil},
		{"empty yields nil, nil", []int{}, nil, nil},
