	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gotMatched, gotRest := Partition(tt.in, isPositive)
			if !reflect.DeepEqual(gotMatched, tt.wantMatched) {
				t.Errorf("Partition(%v) matched = %v, want %v", tt.in, gotMatched, tt.wantMatched)
			}
			if !reflect.DeepEqual(gotRest, tt.wantRest) {
				t.Errorf("Partition(%v) rest = %v, want %v", tt.in, gotRest, tt.wantRest)
			}
		})
	}
}

func TestPartitionEveryElementAppearsExactlyOnce(t *testing.T) {
	in := []int{5, -3, 8, -1, 0, 2}
	matched, rest := Partition(in, func(n int) bool { return n > 0 })
	if len(matched)+len(rest) != len(in) {
		t.Fatalf("len(matched)+len(rest) = %d, want %d", len(matched)+len(rest), len(in))
	}
