	"testing"
)

func TestFlatten(t *testing.T) {
	tests := []struct {
		name string
		in   [][]int
		want []int
	}{
		{"nil outer yields nil", nil, nil},
		{"empty outer yields nil", [][]int{}, nil},
		{"all inner empty yields nil", [][]int{{}, {}, nil}, nil},
		{"single inner", [][]int{{1, 2, 3}}, []int{1, 2, 3}},
		{"multiple inner", [][]int{{1}, {2, 3}, {4, 5, 6}}, []int{1, 2, 3, 4, 5, 6}},
		{"empties interspersed", [][]int{{1}, {}, {2}, nil, {3}}, []int{1, 2, 3}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := Flatten(tt.in)
			if !reflect.DeepEqual(got, tt.want) {
				t.Errorf("Flatten(%v) = %v, want %v", tt.in, got, tt.want)
			}
		})
	}
}

func TestFlattenStrings(t *testing.T) {
	in := [][]string{{"a", "b"}, {"c"}}
	got := Flatten(in)
	want := []string{"a", "b", "c"}
	if !reflect.DeepEqual(got, want) {
		t.Fatalf("Flatten(%v) = %v, want %v", in, got, want)
	}
}

func TestFlattenDoesNotAliasInnerSlices(t *testing.T) {
	// Mutating the result must not reach back into the input slices.
	inner := []int{1, 2}
	in := [][]int{inner, {3, 4}}
