package sandbox

import (
	"errors"
	"strings"
	"testing"
)

func TestWrapErr(t *testing.T) {
	sentinel := errors.New("base failure")

	tests := []struct {
		name    string
		err     error
		msg     string
		wantNil bool
		wantMsg string
		wantIs  bool
	}{
		{
			name:    "nil error returns nil",
			err:     nil,
			msg:     "loading config",
			wantNil: true,
		},
		{
			name:    "wraps sentinel with prefix",
			err:     sentinel,
			msg:     "loading config",
			wantNil: false,
			wantMsg: "loading config: base failure",
			wantIs:  true,
		},
		{
			name:    "empty message still wraps",
			err:     sentinel,
			msg:     "",
			wantNil: false,
			wantMsg: ": base failure",
			wantIs:  true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := WrapErr(tt.err, tt.msg)

			if tt.wantNil {
				if got != nil {
					t.Fatalf("WrapErr(nil, %q) = %v, want nil", tt.msg, got)
				}
				return
			}

			if got == nil {
				t.Fatalf("WrapErr(%v, %q) = nil, want non-nil", tt.err, tt.msg)
			}
			if got.Error() != tt.wantMsg {
				t.Errorf("Error() = %q, want %q", got.Error(), tt.wantMsg)
			}
			if errors.Is(got, sentinel) != tt.wantIs {
				t.Errorf("errors.Is(got, sentinel) = %v, want %v", errors.Is(got, sentinel), tt.wantIs)
			}
			if unwrapped := errors.Unwrap(got); unwrapped != tt.err {
				t.Errorf("errors.Unwrap(got) = %v, want %v", unwrapped, tt.err)
			}
		})
	}

	t.Run("double wrap keeps Is and order", func(t *testing.T) {
		inner := WrapErr(sentinel, "inner")
		outer := WrapErr(inner, "outer")
		if !errors.Is(outer, sentinel) {
			t.Errorf("errors.Is(outer, sentinel) = false, want true")
		}
		if !strings.HasPrefix(outer.Error(), "outer: inner: ") {
			t.Errorf("outer.Error() = %q, want prefix %q", outer.Error(), "outer: inner: ")
		}
	})
}
