func TestRootCause(t *testing.T) {
	base := errors.New("disk full")

	tests := []struct {
		name string
		err  error
		want error
	}{
		{
			name: "nil returns nil",
			err:  nil,
			want: nil,
		},
		{
			name: "unwrapped error returns itself",
			err:  base,
			want: base,
		},
		{
			name: "single wrap returns base",
			err:  fmt.Errorf("write failed: %w", base),
			want: base,
		},
		{
			name: "deep chain returns base",
			err:  fmt.Errorf("handler: %w", fmt.Errorf("service: %w", fmt.Errorf("repo: %w", base))),
			want: base,
		},
		{
			name: "non-wrapping verb does not descend",
			err:  fmt.Errorf("context %v", base),
			want: nil, // sentinel below: compared by identity, so want the formatted err itself
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := RootCause(tt.err)

			// Special case: a %v-formatted error has no Unwrap, so it is
			// its own root.
			if tt.name == "non-wrapping verb does not descend" {
				if got != tt.err {
					t.Fatalf("RootCause() = %v, want the error itself %v", got, tt.err)
				}
				if errors.Is(got, base) {
					t.Errorf("errors.Is(root, base) = true, want false for %%v formatting")
				}
				return
			}

			if got != tt.want {
				t.Fatalf("RootCause() = %v, want %v", got, tt.want)
			}
			if tt.want != nil && !errors.Is(tt.err, got) {
				t.Errorf("errors.Is(original, root) = false, want true")
			}
		})
	}
}
