			gotAs := errors.As(tt.err, &ve)
			if gotAs != tt.wantAs {
				t.Fatalf("errors.As = %v, want %v", gotAs, tt.wantAs)
			}
			if gotAs && ve.Field != tt.wantField {
				t.Errorf("Field = %q, want %q", ve.Field, tt.wantField)
			}
			if got := errors.Is(tt.err, cause); got != tt.wantIs {
				t.Errorf("errors.Is(err, cause) = %v, want %v", got, tt.wantIs)
			}
			if tt.wantMsg != "" && tt.err.Error() != tt.wantMsg {
				t.Errorf("Error() = %q, want %q", tt.err.Error(), tt.wantMsg)
			}
