			err:  fmt.Errorf("handler: %w", WithCode(404, base)),
			want: 404,
		},
		{
			name: "outermost code wins",
			err:  WithCode(500, WithCode(404, base)),
			want: 500,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := CodeOf(tt.err); got != tt.want {
