			}
		})
	}

	t.Run("wrapping preserves the base cause under Is", func(t *testing.T) {
		err := fmt.Errorf("x: %w", WithCode(404, base))
		if !errors.Is(err, base) {
			t.Errorf("errors.Is(err, base) = false, want true")
		}
		if CodeOf(err) != 404 {
			t.Errorf("CodeOf(err) = %d, want 404", CodeOf(err))
