import (
	"bytes"
	"encoding/json"
	"testing"
)

func TestMarshalUser(t *testing.T) {
	tests := []struct {
		name string
		in   User
		want string
	}{
		{
			name: "all fields populated",
			in:   User{Name: "Alice", Email: "alice@example.com", Age: 30},
			want: `{"name":"Alice","email":"alice@example.com","age":30}`,
		},
		{
			name: "omitempty drops empty email and zero age",
			in:   User{Name: "Bob"},
			want: `{"name":"Bob"}`,
		},
		{
			name: "name is always present even when empty",
			in:   User{},
			want: `{"name":""}`,
		},
		{
			name: "age present but email omitted",
			in:   User{Name: "Cleo", Age: 41},
			want: `{"name":"Cleo","age":41}`,
		},
		{
			name: "double quote inside string is escaped",
			in:   User{Name: `say "hi"`},
			want: `{"name":"say \"hi\""}`,
		},
		{
			name: "unicode is preserved verbatim",
			in:   User{Name: "naïve café"},
			want: `{"name":"naïve café"}`,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := MarshalUser(tt.in)
			if err != nil {
				t.Fatalf("MarshalUser(%+v) returned unexpected error: %v", tt.in, err)
			}
			if string(got) != tt.want {
				t.Errorf("MarshalUser(%+v) = %s, want %s", tt.in, got, tt.want)
			}
		})
	}
}

// TestMarshalUserEscapesHTML asserts the default encoder behaviour: the runes
// '<', '>' and '&' are escaped (to <, >, &) so the output is safe
// to embed in HTML, yet still round-trips back to the original value.
func TestMarshalUserEscapesHTML(t *testing.T) {
	got, err := MarshalUser(User{Name: "a<b>&c"})
	if err != nil {
		t.Fatalf("MarshalUser returned unexpected error: %v", err)
	}
	for _, c := range []byte{'<', '>', '&'} {
		if bytes.IndexByte(got, c) != -1 {
			t.Errorf("expected byte %q to be escaped, but it appears raw in %s", string(c), got)
		}
	}
	var back User
	if err := json.Unmarshal(got, &back); err != nil {
		t.Fatalf("Unmarshal of %s failed: %v", got, err)
	}
	if back.Name != "a<b>&c" {
		t.Errorf("round-trip Name = %q, want %q", back.Name, "a<b>&c")
	}
}
