func TestChunkBytesReassembles(t *testing.T) {
	data := []byte("the quick brown fox")
	for _, size := range []int{1, 2, 3, 5, 100} {
		var rebuilt []byte
		for _, c := range ChunkBytes(data, size) {
			if len(c) == 0 {
				t.Fatalf("size %d produced an empty chunk", size)
			}
			if len(c) > size {
				t.Fatalf("size %d produced an oversized chunk of len %d", size, len(c))
			}
