		{"run of 256 splits", bytes.Repeat([]byte{'x'}, 256), []byte{255, 'x', 1, 'x'}},
		{"run of 300 splits", bytes.Repeat([]byte{'z'}, 300), []byte{255, 'z', 45, 'z'}},
