// TestRunLengthEncodeRoundTrip decodes the output and checks it matches the
// original input, and that counts never exceed 255.
func TestRunLengthEncodeRoundTrip(t *testing.T) {
	inputs := [][]byte{
		[]byte(""),
		[]byte("a"),
		[]byte("aaaaabbbccccccccd"),
		bytes.Repeat([]byte{'q'}, 1000),
		[]byte("mississippi"),
	}
	for _, in := range inputs {
		enc := RunLengthEncode(in)
		if len(enc)%2 != 0 {
			t.Fatalf("encoding of %q has odd length %d", in, len(enc))
		}
		var decoded []byte
		for i := 0; i < len(enc); i += 2 {
			count := int(enc[i])
			if count < 1 || count > 255 {
				t.Fatalf("invalid run count %d in encoding of %q", count, in)
			}
			decoded = append(decoded, bytes.Repeat([]byte{enc[i+1]}, count)...)
		}
		if !bytes.Equal(decoded, in) {
			t.Errorf("round trip of %q produced %q", in, decoded)
		}
	}
