// emit returns a channel that yields vals and then closes.
func emit(vals ...int) <-chan int {
	c := make(chan int)
	go func() {
		defer close(c)
		for _, v := range vals {
			c <- v
		}
	}()
	return c
}

func TestMerge(t *testing.T) {
	tests := []struct {
		name   string
		inputs [][]int
		want   []int
	}{
		{"no channels", nil, []int{}},
		{"single channel", [][]int{{1, 2, 3}}, []int{1, 2, 3}},
		{"two channels interleaved", [][]int{{1, 3, 5}, {2, 4, 6}}, []int{1, 2, 3, 4, 5, 6}},
		{"includes empty channels", [][]int{{}, {7, 8}, {}}, []int{7, 8}},
		{"duplicates across channels", [][]int{{1, 1}, {1}}, []int{1, 1, 1}},
		{"all empty", [][]int{{}, {}}, []int{}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			chans := make([]<-chan int, len(tt.inputs))
			for i, in := range tt.inputs {
				chans[i] = emit(in...)
			}

			out := Merge(chans...)
			got := []int{}
			done := make(chan struct{})
			go func() {
				defer close(done)
				for v := range out {
					got = append(got, v)
				}
			}()

			select {
			case <-done:
			case <-time.After(2 * time.Second):
				t.Fatal("Merge did not close output channel within timeout")
			}

			sort.Ints(got)
			if len(got) != len(tt.want) {
				t.Fatalf("got %v (len %d), want %v (len %d)", got, len(got), tt.want, len(tt.want))
			}
			for i := range got {
				if got[i] != tt.want[i] {
					t.Errorf("element %d: got %d, want %d (full %v)", i, got[i], tt.want[i], got)
				}
			}
		})
	}
}
