func TestLazy(t *testing.T) {
	tests := []struct {
		name    string
		callers int
		result  int
	}{
		{"single caller", 1, 42},
		{"few callers", 5, 7},
		{"many concurrent callers", 200, -3},
		{"zero result", 64, 0},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var calls int64
			l := NewLazy(func() int {
				atomic.AddInt64(&calls, 1)
				return tt.result
			})

			results := make([]int, tt.callers)
			var wg sync.WaitGroup
			wg.Add(tt.callers)
			for i := 0; i < tt.callers; i++ {
				go func(idx int) {
					defer wg.Done()
					results[idx] = l.Get()
				}(i)
			}
			wg.Wait()

			if got := atomic.LoadInt64(&calls); got != 1 {
				t.Errorf("init called %d times under %d callers, want exactly 1", got, tt.callers)
			}
			for i, r := range results {
				if r != tt.result {
					t.Errorf("caller %d got %d, want %d", i, r, tt.result)
				}
			}

			// A later sequential Get must still return the cache without re-init.
			if got := l.Get(); got != tt.result {
				t.Errorf("post Get() = %d, want %d", got, tt.result)
			}
			if got := atomic.LoadInt64(&calls); got != 1 {
				t.Errorf("after extra Get, init called %d times, want 1", got)
			}
		})
	}
}
