			want:    []string{"a"},
		},
		{
			name:    "ascending priorities",
			entries: []entry{{"low", 1}, {"mid", 2}, {"high", 3}},
			want:    []string{"high", "mid", "low"},
		},
		{
			name:    "insertion order independent",
			entries: []entry{{"high", 100}, {"low", -3}, {"mid", 7}},
			want:    []string{"high", "mid", "low"},
		},
		{
			name:    "negative priorities",
			entries: []entry{{"a", -1}, {"b", -5}, {"c", -2}},
			want:    []string{"a", "c", "b"},
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			pq := NewPriorityQueue()
			for _, e := range tt.entries {
				pq.Push(e.value, e.priority)
			}
			if got := pq.Len(); got != len(tt.entries) {
				t.Fatalf("Len() = %d, want %d", got, len(tt.entries))
			}
			for i, want := range tt.want {
				got, ok := pq.Pop()
				if !ok {
					t.Fatalf("Pop() #%d returned ok=false, want %q", i, want)
				}
				if got != want {
					t.Errorf("Pop() #%d = %q, want %q", i, got, want)
				}
			}
			if got := pq.Len(); got != 0 {
				t.Errorf("after draining, Len() = %d, want 0", got)
			}
		})
	}
}

