	if v, ok := pq.Pop(); ok || v != "" {
		t.Errorf("Pop() on empty = (%q, %v), want (\"\", false)", v, ok)
	}
}

func TestPriorityQueueTiesAllReturned(t *testing.T) {
	pq := NewPriorityQueue()
	values := []string{"x", "y", "z", "w"}
	for _, v := range values {
		pq.Push(v, 1) // identical priorities
	}
	seen := map[string]bool{}
	for range values {
		v, ok := pq.Pop()
		if !ok {
			t.Fatalf("Pop() returned ok=false too early")
		}
		if seen[v] {
			t.Errorf("value %q returned twice", v)
		}
		seen[v] = true
	}
	for _, v := range values {
		if !seen[v] {
			t.Errorf("value %q was never returned", v)
		}
	}
	if _, ok := pq.Pop(); ok {
		t.Errorf("Pop() after draining returned ok=true")
	}
