func TestReverseList(t *testing.T) {
	tests := []struct {
		name string
		in   []int
		want []int
	}{
		{"nil", nil, nil},
		{"single", []int{1}, []int{1}},
		{"two", []int{1, 2}, []int{2, 1}},
		{"many", []int{1, 2, 3, 4, 5}, []int{5, 4, 3, 2, 1}},
		{"duplicates", []int{7, 7, 8, 7}, []int{7, 8, 7, 7}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := listValues(ReverseList(buildList(tt.in)))
			if !reflect.DeepEqual(got, tt.want) {
				t.Errorf("ReverseList(%v) = %v, want %v", tt.in, got, tt.want)
			}
		})
	}
}

func TestReverseListTwiceIsIdentity(t *testing.T) {
