		t.Errorf("reversing twice = %v, want original %v", got, in)
	}
}

func TestReverseListTerminates(t *testing.T) {
	// After reversal the list must still terminate (no accidental cycle).
	head := ReverseList(buildList([]int{1, 2, 3}))
	count := 0
	for n := head; n != nil; n = n.Next {
		count++
		if count > 3 {
			t.Fatalf("list does not terminate; possible cycle introduced")
		}
	}
	if count != 3 {
		t.Errorf("length after reverse = %d, want 3", count)
	}
