package sandbox

import (
	"errors"
	"reflect"
	"strings"
	"testing"
)

// failingReader yields its data once and then returns a sticky error, used
// to exercise error propagation through bufio.Scanner.
type failingReader struct {
	data []byte
	err  error
	off  int
}

func (f *failingReader) Read(p []byte) (int, error) {
	if f.off < len(f.data) {
		n := copy(p, f.data[f.off:])
		f.off += n
		return n, nil
	}
	return 0, f.err
}

func TestReadLines(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  []string
	}{
		{"empty input yields no lines", "", nil},
		{"single line without newline", "hello", []string{"hello"}},
		{"single line with trailing newline", "hello\n", []string{"hello"}},
		{"several lines", "a\nb\nc", []string{"a", "b", "c"}},
		{"blank line in the middle is preserved", "a\n\nb", []string{"a", "", "b"}},
		{"crlf terminators are stripped", "a\r\nb\r\n", []string{"a", "b"}},
		{"only newlines yield empty lines", "\n\n", []string{"", ""}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := ReadLines(strings.NewReader(tt.input))
			if err != nil {
				t.Fatalf("ReadLines(%q) returned unexpected error: %v", tt.input, err)
			}
			if !reflect.DeepEqual(got, tt.want) {
				t.Errorf("ReadLines(%q) = %#v, want %#v", tt.input, got, tt.want)
			}
		})
	}
}

func TestReadLinesPropagatesError(t *testing.T) {
	sentinel := errors.New("boom")
	r := &failingReader{data: []byte("a\nb\n"), err: sentinel}
	if _, err := ReadLines(r); !errors.Is(err, sentinel) {
		t.Fatalf("ReadLines error = %v, want %v", err, sentinel)
	}
}
