func TestCountingWriter(t *testing.T) {
	tests := []struct {
		name   string
		writes []string
		want   string
	}{
		{"no writes", nil, ""},
		{"single write", []string{"hello"}, "hello"},
		{"multiple writes accumulate", []string{"foo", "bar", "baz"}, "foobarbaz"},
		{"empty writes count as zero", []string{"", "x", ""}, "x"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var buf bytes.Buffer
			cw := NewCountingWriter(&buf)
			for _, s := range tt.writes {
				n, err := cw.Write([]byte(s))
				if err != nil {
					t.Fatalf("Write(%q) returned unexpected error: %v", s, err)
				}
				if n != len(s) {
					t.Errorf("Write(%q) returned n=%d, want %d", s, n, len(s))
				}
			}
			if cw.Total != int64(len(tt.want)) {
				t.Errorf("Total = %d, want %d", cw.Total, len(tt.want))
			}
			if got := buf.String(); got != tt.want {
				t.Errorf("underlying buffer = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestCountingWriterWorksWithIoCopy(t *testing.T) {
	const payload = "streamed data"
	var buf bytes.Buffer
	cw := NewCountingWriter(&buf)

	n, err := io.Copy(cw, bytes.NewReader([]byte(payload)))
	if err != nil {
		t.Fatalf("io.Copy returned unexpected error: %v", err)
	}
	if n != int64(len(payload)) {
		t.Errorf("io.Copy wrote %d bytes, want %d", n, len(payload))
	}
	if cw.Total != n {
		t.Errorf("Total = %d, want %d", cw.Total, n)
	}
	if buf.String() != payload {
		t.Errorf("underlying buffer = %q, want %q", buf.String(), payload)
	}
}
