func TestModPowMatchesNaive(t *testing.T) {
	// Cross-check fast exponentiation against repeated multiplication.
	naive := func(base, exp, mod int) int {
		r := 1
		for i := 0; i < exp; i++ {
			r = (r * base) % mod
		}
		return r
	}
	mod := 97
	for base := 0; base < 50; base++ {
		for exp := 0; exp < 30; exp++ {
			if got, want := ModPow(base, exp, mod), naive(base, exp, mod); got != want {
				t.Fatalf("ModPow(%d, %d, %d) = %d, naive = %d", base, exp, mod, got, want)
			}
		}
