		want float64
	}{
		{"typical", []float64{1, 2, 3}, []float64{4, 5, 6}, 32},
		{"both empty", []float64{}, []float64{}, 0},
		{"orthogonal", []float64{1, 0}, []float64{0, 1}, 0},
