		t.Run(tt.name, func(t *testing.T) {
			got, err := DotProduct(tt.a, tt.b)
			if err != nil {
				t.Fatalf("DotProduct(%v, %v) returned unexpected error: %v", tt.a, tt.b, err)
			}
			if math.Abs(got-tt.want) > eps {
				t.Errorf("DotProduct(%v, %v) = %g, want %g", tt.a, tt.b, got, tt.want)
			}
		})
