func TestDotProductLengthMismatch(t *testing.T) {
	mismatched := []struct {
		a, b []float64
	}{
		{[]float64{1, 2}, []float64{3}},
		{[]float64{}, []float64{1}},
		{[]float64{1, 2, 3}, []float64{1, 2}},
	}

	for _, tt := range mismatched {
		got, err := DotProduct(tt.a, tt.b)
		if !errors.Is(err, ErrLengthMismatch) {
			t.Errorf("DotProduct(%v, %v) error = %v, want ErrLengthMismatch", tt.a, tt.b, err)
		}
		if got != 0 {
			t.Errorf("DotProduct(%v, %v) value = %g, want 0 on error", tt.a, tt.b, got)
		}
	}
