package sandbox

import (
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestRequestIDMiddleware(t *testing.T) {
	tests := []struct {
		name         string
		incomingID   string
		wantHeaderID string
		wantSeenNext string
	}{
		{
			name:         "preserves incoming id",
			incomingID:   "abc-123",
			wantHeaderID: "abc-123",
			wantSeenNext: "abc-123",
		},
		{
			name:         "generates id when missing",
			incomingID:   "",
			wantHeaderID: "default-id",
			wantSeenNext: "default-id",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var seenByNext string
			called := false
			next := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
				called = true
				seenByNext = r.Header.Get("X-Request-ID")
				w.WriteHeader(http.StatusOK)
			})

			req := httptest.NewRequest(http.MethodGet, "/", nil)
			if tt.incomingID != "" {
				req.Header.Set("X-Request-ID", tt.incomingID)
			}
			rec := httptest.NewRecorder()

			RequestIDMiddleware(next).ServeHTTP(rec, req)

			if !called {
				t.Fatal("next handler was not called")
			}
			if got := rec.Header().Get("X-Request-ID"); got != tt.wantHeaderID {
				t.Errorf("response X-Request-ID = %q, want %q", got, tt.wantHeaderID)
			}
			if seenByNext != tt.wantSeenNext {
				t.Errorf("id seen by next = %q, want %q", seenByNext, tt.wantSeenNext)
			}
		})
	}
}
